function toggleFloatWindow(){try{if(!(window.AndroidBridge&&AndroidBridge.toggleFloatingWindow)){toast('当前环境不支持悬浮窗');return}let r=AndroidBridge.toggleFloatingWindow();if(r==='enabled')toast('悬浮窗已开启，点击小圆球可快速记账');else if(r==='disabled')toast('悬浮窗已关闭');else if(r==='need_permission')toast('请允许“秒记账”显示在其他应用上层，授权后返回应用');else toast('悬浮窗状态已更新');setTimeout(()=>{if(currentPage==='mine')renderMine()},500)}catch(e){toast('悬浮窗开启失败，请检查系统权限')}}
