function openReminder(){let parts=(reminder.time||'21:00').split(':');reminderHour=parts[0]||'21';reminderMinute=parts[1]||'00';$('reminderSwitch').classList.toggle('on',!!reminder.enabled);renderTimeWheels();$('reminderPanel').classList.add('show');updateReminderPanelState();setTimeout(()=>{centerWheelValue('hourWheel',reminderHour);centerWheelValue('minuteWheel',reminderMinute);attachReminderWheel('hourWheel','hour');attachReminderWheel('minuteWheel','minute');updateReminderWheelState('hourWheel','hour');updateReminderWheelState('minuteWheel','minute')},80)}function renderTimeWheels(){if($('reminderTimeDisplay'))$('reminderTimeDisplay').textContent=reminderHour+':'+reminderMinute;let hs='',ms='';for(let h=0;h<24;h++){let v=String(h).padStart(2,'0');hs+=`<button class="time-item ${v===reminderHour?'on':''}" data-value="${v}" onclick="setReminderHour('${v}')">${v}</button>`}for(let m=0;m<60;m++){let v=String(m).padStart(2,'0');ms+=`<button class="time-item ${v===reminderMinute?'on':''}" data-value="${v}" onclick="setReminderMinute('${v}')">${v}</button>`}$('hourWheel').innerHTML=hs;$('minuteWheel').innerHTML=ms}function centerWheelValue(id,value){let wheel=$(id);let el=wheel&&wheel.querySelector(`.time-item[data-value="${value}"]`);if(!wheel||!el)return;wheel.scrollTop=el.offsetTop-(wheel.clientHeight-el.offsetHeight)/2}function nearestWheelItem(wheel){let center=wheel.scrollTop+wheel.clientHeight/2;let items=[...wheel.querySelectorAll('.time-item')];let best=items[0],dist=Infinity;items.forEach(it=>{let c=it.offsetTop+it.offsetHeight/2,d=Math.abs(c-center);if(d<dist){dist=d;best=it}});return best}function updateReminderWheelState(id,type,doSnap=false){let wheel=$(id);if(!wheel)return;let item=nearestWheelItem(wheel);if(!item)return;let val=item.dataset.value;if(type==='hour')reminderHour=val;else reminderMinute=val;if($('reminderTimeDisplay'))$('reminderTimeDisplay').textContent=reminderHour+':'+reminderMinute;[...wheel.querySelectorAll('.time-item')].forEach(it=>{it.classList.toggle('on',it===item);let diff=Math.abs((it.offsetTop+it.offsetHeight/2)-(wheel.scrollTop+wheel.clientHeight/2));it.classList.toggle('near',diff<70&&it!==item)});if(doSnap){wheel.scrollTo({top:item.offsetTop-(wheel.clientHeight-item.offsetHeight)/2,behavior:'smooth'})}}function attachReminderWheel(id,type){let wheel=$(id);if(!wheel||wheel.dataset.snapReady)return;wheel.dataset.snapReady='1';let timer=null;wheel.addEventListener('scroll',()=>{updateReminderWheelState(id,type,false);clearTimeout(timer);timer=setTimeout(()=>updateReminderWheelState(id,type,true),120)},{passive:true})}function setReminderHour(v){reminderHour=v;if($('reminderTimeDisplay'))$('reminderTimeDisplay').textContent=reminderHour+':'+reminderMinute;centerWheelValue('hourWheel',v);setTimeout(()=>updateReminderWheelState('hourWheel','hour',true),80)}function setReminderMinute(v){reminderMinute=v;if($('reminderTimeDisplay'))$('reminderTimeDisplay').textContent=reminderHour+':'+reminderMinute;centerWheelValue('minuteWheel',v);setTimeout(()=>updateReminderWheelState('minuteWheel','minute',true),80)}function updateReminderPanelState(){let box=$('reminderPanel')&&$('reminderPanel').querySelector('.panel-box');if(box)box.classList.toggle('reminder-off',!$('reminderSwitch').classList.contains('on'))}function toggleReminderSwitch(){$('reminderSwitch').classList.toggle('on');updateReminderPanelState()}function saveReminder(){reminder={enabled:$('reminderSwitch').classList.contains('on'),time:reminderHour+':'+reminderMinute};saveAll();scheduleReminder();closePanel('reminderPanel');renderMine();toast(reminder.enabled?'提醒已开启':'提醒已关闭')}function scheduleReminder(){try{if(window.AndroidBridge){if(reminder.enabled&&AndroidBridge.scheduleDailyReminder)AndroidBridge.scheduleDailyReminder(reminder.time);if(!reminder.enabled&&AndroidBridge.cancelDailyReminder)AndroidBridge.cancelDailyReminder()}}catch(e){}}function openAbout(){$('aboutPanel').classList.add('show')}async function feedback(){let v=await appPrompt('意见反馈','',{multiline:true,placeholder:'写下你的建议或遇到的问题…'});if(v&&v.trim()){let arr=readJSON('mjz_feedback',[]);arr.push({time:new Date().toISOString(),text:v.trim()});localStorage.mjz_feedback=JSON.stringify(arr);if(window.AndroidBridge&&AndroidBridge.saveFeedback)AndroidBridge.saveFeedback(v.trim());toast('感谢反馈，已保存')}}
function makeBackup(){return JSON.stringify({version:'5.9',exportedAt:new Date().toISOString(),entries,cats,incomeCats,budget,nick,avatar,reminder,theme:currentTheme},null,2)}function backup(){$('textTitle').textContent='备份数据';$('textBox').value=makeBackup();$('backupActions').style.display='flex';$('restoreActions').style.display='none';$('exportPath').style.display='none';$('textPanel').classList.add('show')}function restorePrompt(){$('textTitle').textContent='恢复数据';$('textBox').value='';$('backupActions').style.display='none';$('restoreActions').style.display='flex';$('exportPath').style.display='none';$('textPanel').classList.add('show')}function copyText(){let v=$('textBox').value;navigator.clipboard&&navigator.clipboard.writeText(v);$('textBox').select();document.execCommand('copy');toast('已复制')}function exportFileDirect(){let data=makeBackup();let name='秒记账备份_'+todayStr()+'.json';if(window.AndroidBridge&&AndroidBridge.exportBackupFile){let p=AndroidBridge.exportBackupFile(name,data);toast(p?'已导出到下载目录':'导出失败');return}downloadText(name,data)}function exportFile(){let data=$('textBox').value||makeBackup();let name='秒记账备份_'+todayStr()+'.json';if(window.AndroidBridge&&AndroidBridge.exportBackupFile){let p=AndroidBridge.exportBackupFile(name,data);$('exportPath').textContent=p?'已导出：'+p:'导出失败';$('exportPath').style.display='block';toast(p?'已导出':'导出失败');return}downloadText(name,data)}function downloadText(name,data){let blob=new Blob([data],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}function chooseRestoreFile(){$('restoreFile').value='';$('restoreFile').click()}function backupEntryCount(o){return o&&Array.isArray(o.entries)?o.entries.length:0}function showRestoreInfo(fileName,count){let local=entries.length,msg=`已读取${fileName?'：'+fileName:''}，备份 ${count} 条，当前本地 ${local} 条。请选择合并恢复或替换恢复。`;$('exportPath').textContent=msg;$('exportPath').style.display='block';toast(`已读取备份 ${count} 条，本地 ${local} 条`)}function handleRestoreFile(ev){let f=ev.target.files&&ev.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{let txt=String(r.result||'');$('textBox').value=txt;try{let o=JSON.parse(txt);if(!Array.isArray(o.entries)){toast('未找到账单数据，请确认备份文件包含 entries 字段');return}showRestoreInfo(f.name,backupEntryCount(o))}catch(e){toast('文件不是有效备份，请确认选择的是秒记账导出的 JSON 文件')}};r.readAsText(f,'utf-8')}function normEntry(e){return{amount:Number(e.amount)||0,date:e.date||'',time:e.time||'',name:e.name||'其他',icon:e.icon||'…',note:e.note||''}}function ekey(e){let x=normEntry(e);return [x.date,x.time,x.amount,x.name,x.icon,x.note].join('|')}async function restoreBackup(mode){let txt=$('textBox').value.trim();if(!txt){toast('请先粘贴或导入备份文件');return}try{let o=JSON.parse(txt);if(!Array.isArray(o.entries)){toast('未找到账单数据，请确认备份文件包含 entries 字段');return}let fileCount=o.entries.length,beforeCount=entries.length;if(mode==='replace'){let ok=await appConfirm('确认替换恢复',`替换恢复会清空当前本地数据。\n\n当前本地：${beforeCount} 条\n备份账单：${fileCount} 条\n\n确认继续？`,{danger:true,okText:'继续'});if(!ok)return}if(mode==='merge'){let set=new Set(entries.map(ekey)),added=0,skip=0;o.entries.map(normEntry).forEach(e=>{let k=ekey(e);if(set.has(k))skip++;else{entries.unshift(e);set.add(k);added++}});mergeCatList(cats,o.cats);mergeCatList(incomeCats,o.incomeCats);let afterCount=entries.length;toast(`合并完成：原有 ${beforeCount} 条，新增 ${added} 条，跳过 ${skip} 条，当前共 ${afterCount} 条`)}else{entries=o.entries.map(normEntry);if(Array.isArray(o.cats)&&o.cats.length)cats=o.cats;if(Array.isArray(o.incomeCats)&&o.incomeCats.length)incomeCats=o.incomeCats;budget=isNaN(parseFloat(o.budget))?budget:parseFloat(o.budget);nick=o.nick||nick;avatar=o.avatar||avatar;reminder=o.reminder||reminder;if(o.theme)applyTheme(o.theme);toast(`替换完成：已恢复 ${entries.length} 条账单`)}saveAll();closePanel('textPanel');render()}catch(e){toast('文件不是有效备份，请确认选择的是秒记账导出的 JSON 文件')}}function mergeCatList(target,src){if(!Array.isArray(src))return;let s=new Set(target.map(c=>c[0]+'|'+c[1]));src.forEach(c=>{if(Array.isArray(c)&&c.length>=2&&!s.has(c[0]+'|'+c[1])){target.push([c[0],c[1]]);s.add(c[0]+'|'+c[1])}})}async function clearData(){let ok=await appConfirm('确认清空',`清空后无法恢复。\n\n当前账单：${entries.length} 条\n确认清空所有账单记录？`,{danger:true,okText:'清空'});if(ok){entries=[];saveAll();render();toast('已清空')}}
render();
